 1→import type { Unit } from '@/types/property';
 2→import type { RoomSelection } from '@/Stores/useBookingStore';
 3→
 4→export interface PriceLineItem {
 5→  unitName: string;
 6→  unitPrice: number;
 7→  pricingModel: 'per_unit' | 'per_person';
 8→  quantity: number;
 9→  guests: number;
10→  nights: number;
11→  lineTotal: number;
12→}
13→
14→export interface PriceBreakdown {
15→  lineItems: PriceLineItem[];
16→  subtotal: number;
17→  taxRate: number;
18→  taxAmount: number;
19→  total: number;
20→}
21→
22→export function calculateNights(checkIn: string, checkOut: string): number {
23→  const start = new Date(checkIn);
24→  const end = new Date(checkOut);
25→  const diffMs = end.getTime() - start.getTime();
26→  return Math.max(Math.round(diffMs / (1000 * 60 * 60 * 24)), 0);
27→}
28→
29→export function calculatePrice(
30→  rooms: RoomSelection[],
31→  units: Unit[],
32→  nights: number,
33→  taxRate: number
34→): PriceBreakdown {
35→  const unitMap = new Map(units.map((u) => [u.id, u]));
36→
37→  const lineItems: PriceLineItem[] = rooms
38→    .filter((r) => r.quantity > 0)
39→    .map((room) => {
40→      const unit = unitMap.get(room.unitId);
41→      if (!unit) {
42→        return null;
43→      }
44→
45→      const lineTotal =
46→        unit.pricing_model === 'per_unit'
47→          ? unit.price * nights * room.quantity
48→          : unit.price * room.guests * nights * room.quantity;
49→
50→      return {
51→        unitName: unit.name,
52→        unitPrice: unit.price,
53→        pricingModel: unit.pricing_model,
54→        quantity: room.quantity,
55→        guests: room.guests,
56→        nights,
57→        lineTotal,
58→      };
59→    })
60→    .filter((item): item is PriceLineItem => item !== null);
61→
62→  const subtotal = lineItems.reduce((sum, item) => sum + item.lineTotal, 0);
63→  const taxAmount = subtotal * taxRate;
64→  const total = subtotal + taxAmount;
65→
66→  return { lineItems, subtotal, taxRate, taxAmount, total };
67→}
68→

1→const currencyFormatter = new Intl.NumberFormat('en-ZA', {
2→  style: 'currency',
3→  currency: 'ZAR',
4→});
5→
6→export function formatCurrency(amount: number): string {
7→  return currencyFormatter.format(amount);
8→}
