 1→import { create } from 'zustand';
 2→import { persist } from 'zustand/middleware';
 3→
 4→export interface RoomSelection {
 5→  unitId: number;
 6→  quantity: number;
 7→  guests: number;
 8→}
 9→
10→interface BookingState {
11→  currentStep: number;
12→  checkIn: string | null;
13→  checkOut: string | null;
14→  rooms: RoomSelection[];
15→  specialRequests: string;
16→  bookingId: number | null;
17→}
18→
19→interface BookingActions {
20→  setDates: (checkIn: string, checkOut: string) => void;
21→  setRooms: (rooms: RoomSelection[]) => void;
22→  setSpecialRequests: (requests: string) => void;
23→  setBookingId: (id: number) => void;
24→  nextStep: () => void;
25→  prevStep: () => void;
26→  goToStep: (step: number) => void;
27→  reset: () => void;
28→}
29→
30→const initialState: BookingState = {
31→  currentStep: 1,
32→  checkIn: null,
33→  checkOut: null,
34→  rooms: [],
35→  specialRequests: '',
36→  bookingId: null,
37→};
38→
39→export const useBookingStore = create<BookingState & BookingActions>()(
40→  persist(
41→    (set) => ({
42→      ...initialState,
43→      setDates: (checkIn, checkOut) => set({ checkIn, checkOut }),
44→      setRooms: (rooms) => set({ rooms }),
45→      setSpecialRequests: (specialRequests) => set({ specialRequests }),
46→      setBookingId: (bookingId) => set({ bookingId }),
47→      nextStep: () => set((state) => ({ currentStep: Math.min(state.currentStep + 1, 5) })),
48→      prevStep: () => set((state) => ({ currentStep: Math.max(state.currentStep - 1, 1) })),
49→      goToStep: (step) => set({ currentStep: step }),
50→      reset: () => set(initialState),
51→    }),
52→    { name: 'booking-wizard' }
53→  )
54→);
55→

 1→import { z } from 'zod';
 2→
 3→export const dateSchema = z
 4→  .object({
 5→    checkIn: z
 6→      .string()
 7→      .min(1, 'Check-in date is required')
 8→      .refine((val) => {
 9→        const date = new Date(val);
10→        const today = new Date();
11→        today.setHours(0, 0, 0, 0);
12→        return date >= today;
13→      }, 'Check-in must be today or later'),
14→    checkOut: z.string().min(1, 'Check-out date is required'),
15→  })
16→  .refine(
17→    (data) => {
18→      if (!data.checkIn || !data.checkOut) return true;
19→      return new Date(data.checkOut) > new Date(data.checkIn);
20→    },
21→    { message: 'Check-out must be after check-in', path: ['checkOut'] }
22→  );
23→
24→export type DateFormValues = z.infer<typeof dateSchema>;
25→

 1→import { z } from 'zod';
