import { calculatePrice, calculateNights } from '@/lib/utils/calculatePrice';
import type { Unit } from '@/types/property';
import type { RoomSelection } from '@/Stores/useBookingStore';

const TAX_RATE = 0.15;

const standardRoom: Unit = {
  id: 1,
  name: 'Standard Room',
  max_guests: 2,
  pricing_model: 'per_unit',
  price: 1200,
  available_count: 5,
  pictures: [],
};

const familyCottage: Unit = {
  id: 2,
  name: 'Family Cottage',
  max_guests: 6,
  pricing_model: 'per_person',
  price: 650,
  available_count: 3,
  pictures: [],
};

describe('calculateNights', () => {
  it('calculates nights between two dates', () => {
    expect(calculateNights('2026-04-01', '2026-04-04')).toBe(3);
  });

  it('returns 0 for same-day dates', () => {
    expect(calculateNights('2026-04-01', '2026-04-01')).toBe(0);
  });

  it('returns 0 for inverted dates', () => {
    expect(calculateNights('2026-04-04', '2026-04-01')).toBe(0);
  });
});

describe('calculatePrice', () => {
  it('calculates per_unit price: price * nights * quantity', () => {
    const rooms: RoomSelection[] = [{ unitId: 1, quantity: 2, guests: 2 }];
    const result = calculatePrice(rooms, [standardRoom], 3, TAX_RATE);

    expect(result.lineItems).toHaveLength(1);
    expect(result.lineItems[0].lineTotal).toBe(1200 * 3 * 2); // 7200
  });

  it('calculates per_person price: price * guests * nights * quantity', () => {
    const rooms: RoomSelection[] = [{ unitId: 2, quantity: 1, guests: 4 }];
    const result = calculatePrice(rooms, [familyCottage], 2, TAX_RATE);

    expect(result.lineItems).toHaveLength(1);
    expect(result.lineItems[0].lineTotal).toBe(650 * 4 * 2 * 1); // 5200
  });

  it('sums multi-room total correctly', () => {
    const rooms: RoomSelection[] = [
      { unitId: 1, quantity: 2, guests: 2 },
      { unitId: 2, quantity: 1, guests: 4 },
    ];
    const result = calculatePrice(rooms, [standardRoom, familyCottage], 3, TAX_RATE);

    const expectedStandard = 1200 * 3 * 2; // 7200
    const expectedFamily = 650 * 4 * 3 * 1; // 7800
    expect(result.subtotal).toBe(expectedStandard + expectedFamily); // 15000
  });

  it('calculates VAT at 15%', () => {
    const rooms: RoomSelection[] = [{ unitId: 1, quantity: 1, guests: 1 }];
    const result = calculatePrice(rooms, [standardRoom], 2, TAX_RATE);

    const subtotal = 1200 * 2 * 1; // 2400
    expect(result.taxRate).toBe(0.15);
    expect(result.taxAmount).toBe(subtotal * 0.15); // 360
    expect(result.total).toBe(subtotal + subtotal * 0.15); // 2760
  });

  it('handles edge case: 1 night, 1 guest, 1 quantity', () => {
    const rooms: RoomSelection[] = [{ unitId: 1, quantity: 1, guests: 1 }];
    const result = calculatePrice(rooms, [standardRoom], 1, TAX_RATE);

    expect(result.subtotal).toBe(1200);
    expect(result.total).toBe(1200 * 1.15);
  });

  it('per_unit ignores guests in calculation', () => {
    const rooms1: RoomSelection[] = [{ unitId: 1, quantity: 1, guests: 1 }];
    const rooms2: RoomSelection[] = [{ unitId: 1, quantity: 1, guests: 2 }];

    const result1 = calculatePrice(rooms1, [standardRoom], 2, TAX_RATE);
    const result2 = calculatePrice(rooms2, [standardRoom], 2, TAX_RATE);

    expect(result1.subtotal).toBe(result2.subtotal);
  });

  it('filters out rooms with quantity 0', () => {
    const rooms: RoomSelection[] = [{ unitId: 1, quantity: 0, guests: 2 }];
    const result = calculatePrice(rooms, [standardRoom], 3, TAX_RATE);

    expect(result.lineItems).toHaveLength(0);
    expect(result.subtotal).toBe(0);
  });

  it('skips rooms with unknown unitId', () => {
    const rooms: RoomSelection[] = [{ unitId: 999, quantity: 1, guests: 2 }];
    const result = calculatePrice(rooms, [standardRoom], 3, TAX_RATE);

    expect(result.lineItems).toHaveLength(0);
    expect(result.subtotal).toBe(0);
  });
});

import { formatCurrency } from '@/lib/utils/formatCurrency';

describe('formatCurrency', () => {
  it('formats ZAR with R symbol', () => {
    const result = formatCurrency(1200);
    expect(result).toContain('R');
    expect(result).toContain('1');
    expect(result).toContain('200');
  });

  it('handles zero', () => {
    const result = formatCurrency(0);
    expect(result).toContain('R');
    expect(result).toContain('0');
  });

  it('handles large amounts', () => {
    const result = formatCurrency(1500000);
    expect(result).toContain('R');
    expect(result).toContain('500');
    expect(result).toContain('000');
  });

  it('handles decimal amounts', () => {
    const result = formatCurrency(99.99);
    expect(result).toContain('R');
    expect(result).toContain('99');
  });
});

import { useBookingStore } from '@/Stores/useBookingStore';

describe('useBookingStore', () => {
  beforeEach(() => {
    useBookingStore.getState().reset();
  });

  it('initializes with default state', () => {
    const state = useBookingStore.getState();
    expect(state.currentStep).toBe(1);
    expect(state.checkIn).toBeNull();
    expect(state.checkOut).toBeNull();
    expect(state.rooms).toEqual([]);
    expect(state.specialRequests).toBe('');
    expect(state.bookingId).toBeNull();
  });

  it('sets and retrieves dates', () => {
    useBookingStore.getState().setDates('2026-04-01', '2026-04-04');
    const state = useBookingStore.getState();
    expect(state.checkIn).toBe('2026-04-01');
    expect(state.checkOut).toBe('2026-04-04');
  });

  it('sets and retrieves room selections', () => {
    const rooms = [
      { unitId: 1, quantity: 2, guests: 2 },
      { unitId: 2, quantity: 1, guests: 4 },
    ];
    useBookingStore.getState().setRooms(rooms);
    expect(useBookingStore.getState().rooms).toEqual(rooms);
  });

  it('sets special requests', () => {
    useBookingStore.getState().setSpecialRequests('Late check-in please');
    expect(useBookingStore.getState().specialRequests).toBe('Late check-in please');
  });

  it('sets booking id', () => {
    useBookingStore.getState().setBookingId(42);
    expect(useBookingStore.getState().bookingId).toBe(42);
  });

  describe('step navigation', () => {
    it('navigates to next step', () => {
      useBookingStore.getState().nextStep();
      expect(useBookingStore.getState().currentStep).toBe(2);
    });

    it('navigates to previous step', () => {
      useBookingStore.getState().goToStep(3);
      useBookingStore.getState().prevStep();
      expect(useBookingStore.getState().currentStep).toBe(2);
    });

    it('goes to a specific step', () => {
      useBookingStore.getState().goToStep(4);
      expect(useBookingStore.getState().currentStep).toBe(4);
    });

    it('clamps nextStep at upper bound (5)', () => {
      useBookingStore.getState().goToStep(5);
      useBookingStore.getState().nextStep();
      expect(useBookingStore.getState().currentStep).toBe(5);
    });

    it('clamps prevStep at lower bound (1)', () => {
      useBookingStore.getState().prevStep();
      expect(useBookingStore.getState().currentStep).toBe(1);
    });
  });

  it('reset clears all state', () => {
    useBookingStore.getState().setDates('2026-04-01', '2026-04-04');
    useBookingStore.getState().setRooms([{ unitId: 1, quantity: 1, guests: 2 }]);
    useBookingStore.getState().setSpecialRequests('Test');
    useBookingStore.getState().setBookingId(99);
    useBookingStore.getState().nextStep();

    useBookingStore.getState().reset();
    const state = useBookingStore.getState();

    expect(state.currentStep).toBe(1);
    expect(state.checkIn).toBeNull();
    expect(state.checkOut).toBeNull();
    expect(state.rooms).toEqual([]);
    expect(state.specialRequests).toBe('');
    expect(state.bookingId).toBeNull();
  });
});

import { dateSchema } from '@/lib/schemas/dateSchema';
import { roomSchema } from '@/lib/schemas/roomSchema';
import { bookingSchema } from '@/lib/schemas/bookingSchema';

describe('dateSchema', () => {
  it('accepts a valid date range', () => {
    const result = dateSchema.safeParse({
      checkIn: '2026-12-01',
      checkOut: '2026-12-05',
    });
    expect(result.success).toBe(true);
  });

  it('rejects past check-in date', () => {
    const result = dateSchema.safeParse({
      checkIn: '2020-01-01',
      checkOut: '2020-01-05',
    });
    expect(result.success).toBe(false);
  });

  it('rejects inverted dates (check-out before check-in)', () => {
    const result = dateSchema.safeParse({
      checkIn: '2026-12-05',
      checkOut: '2026-12-01',
    });
    expect(result.success).toBe(false);
  });

  it('rejects missing check-in', () => {
    const result = dateSchema.safeParse({
      checkIn: '',
      checkOut: '2026-12-05',
    });
    expect(result.success).toBe(false);
  });

  it('rejects missing check-out', () => {
    const result = dateSchema.safeParse({
      checkIn: '2026-12-01',
      checkOut: '',
    });
    expect(result.success).toBe(false);
  });
});

describe('roomSchema', () => {
  it('accepts valid room selections with at least one room', () => {
    const result = roomSchema.safeParse({
      rooms: [{ unitId: 1, quantity: 1, guests: 2 }],
    });
    expect(result.success).toBe(true);
  });

  it('rejects when no rooms have quantity > 0', () => {
    const result = roomSchema.safeParse({
      rooms: [{ unitId: 1, quantity: 0, guests: 0 }],
    });
    expect(result.success).toBe(false);
  });

  it('rejects negative quantity', () => {
    const result = roomSchema.safeParse({
      rooms: [{ unitId: 1, quantity: -1, guests: 2 }],
    });
    expect(result.success).toBe(false);
  });

  it('rejects negative guests', () => {
    const result = roomSchema.safeParse({
      rooms: [{ unitId: 1, quantity: 1, guests: -1 }],
    });
    expect(result.success).toBe(false);
  });

  it('accepts multiple rooms where at least one has quantity > 0', () => {
    const result = roomSchema.safeParse({
      rooms: [
        { unitId: 1, quantity: 0, guests: 0 },
        { unitId: 2, quantity: 1, guests: 3 },
      ],
    });
    expect(result.success).toBe(true);
  });
});

describe('bookingSchema', () => {
  const validBooking = {
    checkIn: '2026-12-01',
    checkOut: '2026-12-05',
    rooms: [{ unitId: 1, quantity: 1, guests: 2 }],
    specialRequests: 'Late check-in',
  };

  it('accepts a valid complete booking', () => {
    const result = bookingSchema.safeParse(validBooking);
    expect(result.success).toBe(true);
  });

  it('rejects missing check-in', () => {
    const result = bookingSchema.safeParse({ ...validBooking, checkIn: '' });
    expect(result.success).toBe(false);
  });

  it('rejects inverted dates', () => {
    const result = bookingSchema.safeParse({
      ...validBooking,
      checkIn: '2026-12-05',
      checkOut: '2026-12-01',
    });
    expect(result.success).toBe(false);
  });

  it('rejects when no rooms are selected', () => {
    const result = bookingSchema.safeParse({
      ...validBooking,
      rooms: [{ unitId: 1, quantity: 0, guests: 0 }],
    });
    expect(result.success).toBe(false);
  });

  it('accepts booking without special requests', () => {
    const { specialRequests, ...withoutRequests } = validBooking;
    const result = bookingSchema.safeParse(withoutRequests);
    expect(result.success).toBe(true);
  });

  it('rejects special requests over 500 characters', () => {
    const result = bookingSchema.safeParse({
      ...validBooking,
      specialRequests: 'a'.repeat(501),
    });
    expect(result.success).toBe(false);
  });
});
